#include <bits/stdc++.h>
using namespace std;
const int N=1000005;
//t->max_  taba->tag2  tabe->tag1  tabeq->used
//( a<<1 ) -> ( a*2 )  ( a<<1|1 ) -> ( a*2+1 )
long long n,q,a[N],t[4*N],tabe[4*N],taba[4*N];
bool tabeq[4*N];
void push_up(int u)
{
	t[u]=max(t[u*2],t[u*2+1]);
}
void build(int u,int l,int r)
{
	if(l==r)
	{
		t[u]=a[l];
		return ;
	}
	int mid=(l+r)>>1;
	build(u*2,l,mid);
	build(u*2+1,mid+1,r);
	push_up(u);
}
void pushdown(int u)
{
    int ls=u<<1,rs=(u<<1)+1;
	if(tabeq[u])
	{
        taba[ls]=taba[rs]=0;
    	tabe[ls]=tabe[rs]=tabe[u];
		taba[ls]=taba[rs]=taba[u];
		t[ls]=t[rs]=tabe[u]+taba[u];
    	tabeq[ls]=tabeq[rs]=true;
	}
	else
	{
		taba[ls]+=taba[u];
		taba[rs]+=taba[u];
		t[ls]+=taba[u];
		t[rs]+=taba[u];
		// tabe[ls]+=taba[u];
		// tabe[rs]+=taba[u];
	}
	tabe[u]=taba[u]=tabeq[u]=0;
}
void change(int u,int l,int r,int x,int y,long long k)
{
	if(l>=x&&r<=y)
	{
		t[u]=k;
		tabe[u]=k;
        taba[u]=0;
        tabeq[u]=true;
		return ;
	}
	int mid=(l+r)>>1;
    pushdown(u);
	if(x<=mid) change(u*2,l,mid,x,y,k);
	if(y>mid) change(u*2+1,mid+1,r,x,y,k);
	push_up(u);
}
void update(int u,int l,int r,int x,int y,long long k)
{
	if(l>=x&&r<=y)
	{
		t[u]+=k;
		taba[u]=(taba[u]+k);
		return ;
	}
	int mid=(l+r)/2;
    pushdown(u);
	if(x<=mid) update(u*2,l,mid,x,y,k);
	if(y>mid) update(u*2+1,mid+1,r,x,y,k);
	push_up(u);
}
long long maxx(int u,int l,int r,int x,int y)
{
	if(l>=x&&r<=y) return t[u];
	int mid=(l+r)/2;
	long long ans=-0x3f3f3f3f;
    pushdown(u);
	if(x<=mid) ans=max(ans,maxx(u*2,l,mid,x,y));
	if(y>mid) ans=max(ans,maxx(u*2+1,mid+1,r,x,y));
	return ans;
}
void print(int u,int l,int r)
{
	if(l==r)
	{
		cout<<"          "<<l<<"  num="<<t[u]<<"   taba:"<<taba[u]<<"   tabe:";
		if(tabeq[u]) cout<<tabe[u];
		else cout<<"----";
		cout<<"\n";
		return ;
	}
	cout<<l<<"--"<<r<<"  min:"<<t[u]<<'\n';
	int mid=(l+r)>>1;
	print(u*2,l,mid);
	print(u*2+1,mid+1,r);
	push_up(u);
}
int main()
{
    cin>>n>>q;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	build(1,1,n);
    while(q--)
    {
        int op,l,r,k;
        cin>>op>>l>>r;
		// print(1,1,n);
		// cout<<"_______________\n";
        if(op==1)
        {
            cin>>k;
            change(1,1,n,l,r,k);
        }
        else if(op==2)
        {
            cin>>k;
            update(1,1,n,l,r,k);
        }
        else cout<<maxx(1,1,n,l,r)<<"\n";
    }
    return 0;
}
